import React, { useEffect, useState } from 'react';
import { getApiBase } from '../api/client';

const TOKEN_KEY = 'st_admin_token';

function getToken() {
  return sessionStorage.getItem(TOKEN_KEY) || 'dev-admin-token';
}

export default function AdminPage() {
  const [raw, setRaw] = useState('');
  const [status, setStatus] = useState('');
  const [stats, setStats] = useState(null);

  function load() {
    const token = getToken();
    fetch(`${getApiBase()}/api/admin/summary`, {
      headers: { 'X-Admin-Token': token },
    })
      .then((r) => (r.ok ? r.json() : Promise.reject(new Error('Unauthorized or server error'))))
      .then((data) => {
        setStats(data.stats);
        setRaw(JSON.stringify(data.destinations || [], null, 2));
        setStatus('Loaded from API');
      })
      .catch((e) => {
        setStatus(e.message);
      });
  }

  useEffect(() => {
    load();
  }, []);

  function setToken() {
    const t = window.prompt('Admin token (set ADMIN_TOKEN in backend .env)', getToken());
    if (t) sessionStorage.setItem(TOKEN_KEY, t);
    load();
  }

  return (
    <div className="page page-admin">
      <h1>Admin — destinations &amp; stats</h1>
      <p className="muted">Reads destination rows from MySQL. Update rows here and extend the API if you need write access.</p>
      <p>
        <button type="button" className="btn small" onClick={setToken}>
          Set admin token
        </button>
        <button type="button" className="btn-outline small" onClick={load} style={{ marginLeft: 8 }}>
          Refresh
        </button>
      </p>
      {stats && (
        <p>
          Users: {stats.user_count} &middot; Destinations: {stats.destination_count} &middot; Trips: {stats.trip_count}
        </p>
      )}
      <div style={{ marginTop: 12 }}>
        <textarea
          value={raw}
          onChange={(e) => setRaw(e.target.value)}
          style={{ width: '100%', height: 420, fontFamily: 'monospace', fontSize: 12 }}
        />
      </div>
      <div style={{ marginTop: 8 }}>{status}</div>
    </div>
  );
}
